class BiometricUtil(private val context: Context) {

    private val TAG = "BiometricUtil"
    private lateinit var biometricPrompt: BiometricPrompt
    private lateinit var executive: Executive

    init {
        if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.M) {
            val fm = FingerprintManagerCompat.from(context)
            executive = if (fm.isHardwareDetected && fm.hasEnrolledFingerprints()) {
                Executive(biometricPrompt, fm, context)
            } else Executive()
        } else {
            Log.e(TAG, "Older than Android M, biometrics not supported")
        }
    }

    fun authenticate(callback: (Boolean) -> Unit) {
        executive.authenticate { authenticated ->
            callback(authenticated)
            saveAuthenticatedStatus(context, authenticated)
        }
    }
}

class Executive(private val biometricPrompt: BiometricPrompt, private val fm: FingerprintManagerCompat, private val context: Context) {

    fun authenticate(callback: (Boolean) -> Unit) {
        if (!fm.isEnrolled) {
            callback(false)
            return
        }

        val cryptoObject = FingerprintManagerCompat.createCryptoObject(null)
        val promptInfo = BiometricPrompt.Authenticators.BIOMETRIC_STRONG or BiometricPrompt.Authenticators.DEVICE_CREDENTIAL
        biometricPrompt = BiometricPrompt(context, promptInfo, object : BiometricPrompt.AuthenticationCallback() {
            override fun onAuthenticationError(errorCode: Int, errString: CharSequence) {
                super.onAuthenticationError(errorCode, errString)
                callback(false)
            }

            override fun onAuthenticationSucceeded(result: BiometricPrompt.AuthenticationResult) {
                super.onAuthenticationSucceeded(result)
                callback(true)
            }
        })

        biometricPrompt.authenticate(FingerprintManagerCompat.AuthenticatorIntent(context, cryptoObject).apply {
            flags = Intent.FLAG_ACTIVITY_EXCLUDE_FROM_RECENTS or Intent.FLAG_ACTIVITY_NEW_TASK or Intent.FLAG_ACTIVITY_NO_HISTORY
        }, this)
    }
}

class BiometricAuthActivity : AppCompatActivity() {
    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        if (intent.getBooleanExtra("BIOMETRIC_REQUIRED", false)) {
            val biometricUtil = BiometricUtil(this)
            biometricUtil.authenticate { authenticated ->
                if (!authenticated) {
                    startActivity(Intent(this, LoginActivity::class.java))
                }
            }
        } else {
            startActivity(Intent(this, MainActivity::class.java))
        }
    }
}

fun saveAuthenticatedStatus(context: Context, authenticated: Boolean) {
    val sharedPreferences = context.getSharedPreferences("biometric_prefs", Context.MODE_PRIVATE)
    val editor = sharedPreferences.edit()
    editor.putBoolean("authenticated", authenticated)
    editor.apply()
}